class Solution:
  def solve(self, documents):
    def generate_pipeline(doc):
      if len(doc) == 0:
        return []
      pipeline = []
      for key in doc:
        if isinstance(doc[key], dict):
          pipeline.append({ '$project': { key: 1 } })
          if len(doc[key]) == 0:
            pipeline.append({ '$ifNull': [{ '$project': { key: 1 } }] })
      return pipeline

    pipelines = []
    for doc in documents:
      pipelines.append(generate_pipeline(doc))
    return pipelines

# Call the solve function with some sample input
documents = [{"a": 1, "b": {"c": 2, "d": None}}, {"a": 2, "b": {"c": 3, "e": {"f": 4}}}]
print(solve(documents))
